override fun onLocationChanged(location: android.location.Location) {
    if (LockManager.isWhisperMode(applicationContext)) {
        val isMock = if (android.os.Build.VERSION.SDK_INT >= 31) location.isMock else @Suppress("DEPRECATION") location.isFromMockProvider
        if (isMock) {
            DebugLogger.log("WHISPER_GPS_WARN", "Mock Location Detected. Stop Cheating.")
            return
        }

        // LOGGING: GPS Raw Data
        DebugLogger.log("WHISPER_GPS_RAW", "Accuracy: ${location.accuracy}m | Alt: ${location.altitude}m")

        // ACCURACY FILTER: Changed from 25f to 12f
        if (location.accuracy > 12f) {
            DebugLogger.log("WHISPER_GPS_REJECT", "Low Accuracy (${location.accuracy}m > 12m). Discarded.")
            return
        }

        val start = LockManager.startLocation
        if (start == null) {
            if (locationSettlementCount < 2) {
                locationSettlementCount++
                DebugLogger.log("WHISPER_GPS_SETTLE", "Settling... ($locationSettlementCount/2)")
                return
            }
            LockManager.startLocation = location
            lastLocation = location
            LockManager.currentDisplacement = 0f
            DebugLogger.log("WHISPER_GPS_ANCHOR", "Stable Anchor Locked at ${location.accuracy}m accuracy.")
        } else {
            val prev = lastLocation ?: start
            val delta = prev.distanceTo(location)

            // Movement Filtering: Ignore jitter < 0.6m, reject jumps > 15m (Speed check)
            if (delta < 0.6f) return
            if (delta > 15f) {
                DebugLogger.log("WHISPER_GPS_WARN", "Teleportation detected? Delta=${delta}m rejected.")
                return
            }

            // Distance needs at least one step to 'unlock' tracking
            val steps = LockManager.whisperSteps
            if (steps > 0) {
                LockManager.currentDisplacement += delta
                lastLocation = location
                DebugLogger.log("WHISPER_GPS_OK", "Dist Update: +${String.format("%.1f", delta)}m | Total: ${String.format("%.1f", LockManager.currentDisplacement)}m")

                if (steps >= 30 && LockManager.currentDisplacement >= 12f) {
                    LockManager.stopWhisperMode(applicationContext)
                    stopLocationTracking()
                }
            } else {
                DebugLogger.log("WHISPER_GPS_WAIT", "GPS valid but waiting for first Step sensor event.")
            }
        }
    }
}

